import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;

/**
 * FREIGHT - packed decimal (COMP-3) at the file boundary, translated from
 * COBOL 85. Faithful variant: exact COBOL behavior over Java idiom.
 *
 * The working-storage COMP-3 items (WS-WEIGHT, WS-RATE, WS-CHARGE) are
 * value-identical to DISPLAY numerics (docs/comp3.md), so they are plain
 * BigDecimals here; packed storage becomes observable only in the output
 * record, which this translation encodes with an explicit COMP-3 codec:
 * ceil((digits+1)/2) bytes, one digit per nibble right-aligned against
 * the sign nibble, leading pad nibble 0, sign C (positive or zero) / D
 * (negative) for signed pictures and F for unsigned. The record is
 * written to a real temp file standing in for freight.dat (LINE
 * SEQUENTIAL: record bytes then '\n'), read back, and serialized as the
 * FILEHEX= lowercase-hex line, mirroring the harness wrapper contract.
 */
public final class Freight {

    /** WS-RATE PIC 9V999 COMP-3 VALUE 0.245. */
    private static final BigDecimal RATE = new BigDecimal("0.245");

    /** IF WS-CHARGE > 150.00. */
    private static final BigDecimal TIER_LIMIT = new BigDecimal("150.00");

    /** PIC 9(4)V9 integer capacity (WS-WEIGHT / FR-WEIGHT). */
    private static final BigDecimal PIC_9_4_V9_MODULUS = new BigDecimal("10000");

    /** PIC S9(5)V99 integer capacity (WS-CHARGE / FR-CHARGE). */
    private static final BigDecimal PIC_S9_5_V99_MODULUS = new BigDecimal("100000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        String shipId = readLine(in);                       // WS-SHIP-ID PIC X(8)
        String weightText = readLine(in);                   // WS-WT-TEXT PIC X(10)

        // COMPUTE WS-WEIGHT = FUNCTION NUMVAL(WS-WT-TEXT): the store into
        // PIC 9(4)V9 truncates to one decimal and drops integer overflow.
        BigDecimal weight = numval(weightText, 1, PIC_9_4_V9_MODULUS);

        // COMPUTE WS-CHARGE ROUNDED = WS-WEIGHT * WS-RATE.
        BigDecimal charge = weight.multiply(RATE)
                .setScale(2, RoundingMode.HALF_UP)
                .remainder(PIC_S9_5_V99_MODULUS);

        // IF WS-CHARGE > 150.00 ... ELSE ...: WS-TIER PIC X(4).
        String tier = charge.compareTo(TIER_LIMIT) > 0 ? "BULK" : "STD ";

        // OPEN OUTPUT / MOVE FRT= + weight + charge into the record /
        // WRITE / CLOSE: build the packed record and write it.
        Path recordFile = writeRecord(weight, charge);

        StringBuilder out = new StringBuilder();
        out.append("SHIP_ID=").append(shipId).append('\n');
        out.append("CHARGE=").append(charge.toPlainString()).append('\n');
        out.append("TIER=").append(tier).append('\n');
        System.out.print(out);

        // Serialize the file's actual contents (read back, not echoed) as
        // one lowercase-hex line, mirroring the hex-serializing wrapper.
        serializeHexAndDelete(recordFile);
    }

    /** The freight.dat record: FR-TAG "FRT=" + two COMP-3 fields + '\n'. */
    private static Path writeRecord(BigDecimal weight, BigDecimal charge) throws IOException {
        byte[] tag = "FRT=".getBytes(StandardCharsets.US_ASCII);
        byte[] packedWeight = packed(weight, 5, 1, false);  // FR-WEIGHT PIC 9(4)V9 COMP-3
        byte[] packedCharge = packed(charge, 7, 2, true);   // FR-CHARGE PIC S9(5)V99 COMP-3
        byte[] record = new byte[tag.length + packedWeight.length + packedCharge.length + 1];
        int at = 0;
        System.arraycopy(tag, 0, record, at, tag.length);
        at += tag.length;
        System.arraycopy(packedWeight, 0, record, at, packedWeight.length);
        at += packedWeight.length;
        System.arraycopy(packedCharge, 0, record, at, packedCharge.length);
        at += packedCharge.length;
        record[at] = '\n';                                  // LINE SEQUENTIAL delimiter
        Path file = Files.createTempFile("freight", ".dat");
        Files.write(file, record);
        return file;
    }

    /**
     * COMP-3 packed encoder (docs/comp3.md, validated against GnuCOBOL
     * byte-for-byte): the value scaled to an integer digit string, one
     * digit per nibble right-aligned against the trailing sign nibble,
     * leading pad nibble 0; sign C for positive or zero, D for negative
     * (signed pictures), F for unsigned pictures.
     */
    private static byte[] packed(BigDecimal value, int digits, int scale, boolean signed) {
        boolean negative = value.signum() < 0;
        String ds = value.movePointRight(scale).abs().toBigInteger().toString();
        int byteCount = (digits + 2) / 2;                   // ceil((digits + 1) / 2)
        int digitSlots = byteCount * 2 - 1;
        StringBuilder all = new StringBuilder();
        for (int i = ds.length(); i < digitSlots; i = i + 1) {
            all.append('0');
        }
        all.append(ds);
        int sign = signed ? (negative ? 0xD : 0xC) : 0xF;
        byte[] out = new byte[byteCount];
        for (int i = 0; i < digitSlots; i = i + 1) {
            int nibble = all.charAt(i) - '0';
            if (i % 2 == 0) {
                out[i / 2] = (byte) (nibble << 4);
            } else {
                out[i / 2] |= (byte) nibble;
            }
        }
        out[byteCount - 1] |= (byte) sign;
        return out;
    }

    /** Emit FILEHEX=<lowercase hex of the file bytes>, then remove it. */
    private static void serializeHexAndDelete(Path file) throws IOException {
        byte[] bytes = Files.readAllBytes(file);
        StringBuilder hex = new StringBuilder("FILEHEX=");
        for (int i = 0; i < bytes.length; i = i + 1) {
            hex.append(String.format("%02x", bytes[i] & 0xff));
        }
        System.out.println(hex);
        System.out.flush();
        Files.deleteIfExists(file);
    }

    /** ACCEPT: one value per stdin line. */
    private static String readLine(BufferedReader in) throws IOException {
        String line = in.readLine();
        if (line == null) {
            System.err.println("FREIGHT: missing input line");
            System.exit(3);
        }
        return line.trim();
    }

    /** FUNCTION NUMVAL then the store into the numeric picture. */
    private static BigDecimal numval(String s, int scale, BigDecimal capacity) {
        try {
            return new BigDecimal(s.trim()).setScale(scale, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("FREIGHT: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
